macro.implementation:
do {
  if ((gptp)->oneshot) {
    gpt_lld_stop_timer(gptp);
    (gptp)->oneshot = false;
    __cbdrv_invoke_complete_cb(gptp);
  }
  else {
    __cbdrv_invoke_cb(gptp);
  }
} while (false)

types.verbatim:
typedef hal_gpt_driver_c GPTDriver;
typedef hal_gpt_config_t GPTConfig;

typedef enum {
  GPT_UNINIT = HAL_DRV_STATE_UNINIT,
  GPT_STOP = HAL_DRV_STATE_STOP,
  GPT_READY = HAL_DRV_STATE_READY,
  GPT_CONTINUOUS = HAL_DRV_STATE_ACTIVE,
  GPT_ONESHOT = HAL_DRV_STATE_ACTIVE
} gptstate_t;

typedef void (*gptcallback_t)(GPTDriver *gptp);

/* Inclusion of LLD header.*/
#include "hal_gpt_lld.h"

method.implementation:
msg_t msg;

osalDbgCheck(self != NULL);

if (config != NULL) {
  msg = drvSetCfgX(self, config);
  if (msg != HAL_RET_SUCCESS) {
    return msg;
  }
  drvSetCallbackX(self, (drv_cb_t)config->callback);
}

return drvStart(self);

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_ACTIVE) && !self->oneshot,
              "invalid state");

gpt_lld_change_interval(self, interval);

osalDbgCheck(self != NULL);

osalSysLock();
gptChangeIntervalI(self, interval);
osalSysUnlock();

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");

self->oneshot = false;
self->state = HAL_DRV_STATE_ACTIVE;
gpt_lld_start_timer(self, interval);

osalDbgCheck(self != NULL);

osalSysLock();
gptStartContinuousI(self, interval);
osalSysUnlock();

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert(drvGetCallbackX(self) != NULL, "callback not set");
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");

self->oneshot = true;
self->state = HAL_DRV_STATE_ACTIVE;
gpt_lld_start_timer(self, interval);

osalDbgCheck(self != NULL);

osalSysLock();
gptStartOneShotI(self, interval);
osalSysUnlock();

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_READY) ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_COMPLETE),
              "invalid state");

self->oneshot = false;
self->state = HAL_DRV_STATE_READY;
gpt_lld_stop_timer(self);

osalDbgCheck(self != NULL);
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");

gpt_lld_polled_delay(self, interval);

msg_t msg;

self->oneshot = false;
msg = gpt_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
}

return msg;
